customEChartConfig:
{{ ((chartType) => ( 
(() => {
  const raw = Renewal_List.filteredTableData || Renewal_List.tableData || [];
  const data = raw
    .filter(r => r.contract_expired_date)
    .reduce((acc, r) => {
      const dateObj = new Date(r.contract_expired_date);

      const year = dateObj.getFullYear();
      const month = String(dateObj.getMonth() + 1).padStart(2, '0');
      const monthKey = `${year}-${month}`;

      const rawStatus = (r.Status ?? '').toString().trim();

      // Wenn Status leer → prüfe days_until_expiration
      let status;
      if (!rawStatus) {
        const daysUntil = r.days_until_expiration;
        // Im Window (≤180) → To Assess
        // Außerhalb Window (>180) → Upcoming
        status = daysUntil <= 180 ? 'To Assess' : 'Upcoming';
      } else {
        status = rawStatus;
      }

      if (!acc[monthKey]) acc[monthKey] = {};
      acc[monthKey][status] = (acc[monthKey][status] || 0) + 1;

      return acc;
    }, {});

  const months = Object.keys(data).sort();
  const statuses = ['Upcoming', 'To Assess', 'Low Risk', 'At Risk', 'Closed Won', 'Renewal Lost'];

  const colors = {
    'Upcoming': '#757575',       // Dunkleres Grau
    'To Assess': '#BDBDBD',      // Hellgrau
    'Low Risk': '#9ccc65',       // Hellgrün
    'At Risk': '#e53935',        // Rot
    'Closed Won': '#13734b',     // Dunkelgrün
    'Renewal Lost': '#800020'    // Dunkelrot
  };

  // Calculate max value for dynamic y-axis interval
  const maxValue = Math.max(...months.map(month => {
    return statuses.reduce((sum, status) => sum + (data[month]?.[status] || 0), 0);
  }));

  // Dynamic interval based on max value
  let yAxisInterval;
  if (maxValue <= 30) {
    yAxisInterval = 5;
  } else if (maxValue <= 100) {
    yAxisInterval = 20;
  } else if (maxValue <= 200) {
    yAxisInterval = 50;
  } else {
    yAxisInterval = 100;
  }

  return {
    tooltip: { 
      trigger: 'axis', 
      axisPointer: { type: 'shadow' }
    },
    legend: { 
      data: statuses,
      bottom: 0
    },
    grid: { 
      left: '3%', 
      right: '4%', 
      top: '3%',
      bottom: '12%',
      containLabel: true 
    },
    xAxis: {
      type: 'category',
      data: months,
      axisLabel: {
        formatter: value => {
          const [year, month] = value.split('-');
          const monthNames = ['Jan', 'Feb', 'Mär', 'Apr', 'Mai', 'Jun', 
                             'Jul', 'Aug', 'Sep', 'Okt', 'Nov', 'Dez'];
          return `${monthNames[parseInt(month) - 1]} ${year.slice(2)}`;
        },
        rotate: 45
      }
    },
    yAxis: { 
      type: 'value',
      interval: yAxisInterval,
      minInterval: yAxisInterval
    },
    series: statuses.map(status => ({
      name: status,
      type: 'bar',
      stack: 'total',
      emphasis: { focus: 'series' },
      itemStyle: { color: colors[status] || '#CCCCCC' },
      label: {
        show: true,
        position: 'inside',
        fontWeight: 'normal',
        fontSize: 10,
        color: status === 'Low Risk' || status === 'To Assess' ? '#000' : '#fff',
        formatter: params => params.value >= 1 ? params.value : ''
      },
      data: months.map(month => (data[month]?.[status] ?? 0))
    }))
  };
})()
))(RiskTimelineChart.chartType) }}
